// Slide off of the impacting surface
export var pm_clipVelocity = (vector, normal, overbounce) => {
  let backoff = vec3_dot(vector, normal);

  if (backoff < 0) {
    backoff *= overbounce;
  } else {
    backoff /= overbounce;
  }

  return vec3_addScaledVector(vector, normal, -backoff);
};

